DarkRPUI=DarkRPUI or {}; DarkRPUI.Scoreboard=DarkRPUI.Scoreboard or {}; function DarkRPUI.Scoreboard.BuildColumnEditor(parent) parent:Clear(); DarkRPUI.UI.SectionTitle(parent,"COLUMN CONFIGURATION","Enable, order, and preview registered columns."); local grid=vgui.Create("DIconLayout",parent); grid:Dock(FILL); for id,c in pairs(DarkRPUI.Scoreboard.Columns or {}) do local card=DarkRPUI.UI.MakeAnimatedCard(grid,c.name or id,"Width "..(c.width or 80).." • "..id); card:SetSize(240,92) end end
